import 'package:flutter/material.dart';class SearchScreen extends StatefulWidget {  const SearchScreen({super.key});  @override  State<SearchScreen> createState() => _SearchScreenState();}class _SearchScreenState extends State<SearchScreen>    with SingleTickerProviderStateMixin {  late AnimationController _controller;  @override  void initState() {    super.initState();    _controller = AnimationController(vsync: this);  }  @override  void dispose() {    _controller.dispose();    super.dispose();  }  @override  Widget build(BuildContext context) {    return AnimatedBuilder(      animation: _controller,      builder: (context, child) => Container(),    );  }}